/**
 * Provides a utility function to determine whether a graphic's origin is a [VectorTileGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/VectorTileGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a VectorTileLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isVectorTileGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a VectorTileLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a VectorTileLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type VectorTileGraphicOrigin from "./VectorTileGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [VectorTileGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/VectorTileGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [VectorTileGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/VectorTileGraphicOrigin/), `false` otherwise.
 */
export function isVectorTileGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is VectorTileGraphicOrigin;